# Project: 02-scheduled-fetch
# Description: Fetches San Francisco weather every minute from Open-Meteo and logs the result.

note = Annotation {
  label: "About This Project"
  content: ```
## Scheduled Weather Fetch

This project fetches current weather data for San Francisco from the Open-Meteo API on a recurring schedule.

**How it works:**
1. The Cron trigger fires on schedule (default: every minute)
2. An HTTP request fetches current conditions from Open-Meteo
3. The response is parsed into temperature, wind speed, and humidity
4. Results are logged to the Weather Log, errors to the Error Log

---

**WARNING: This project runs continuously until you stop it.** Every trigger fires a full execution. If you're just testing, run it, watch a few results come through, then stop. Leaving it running indefinitely will accumulate usage on your account.
  ```
}

cron = Cron {
  label: "Every Minute"
  cron: "* * * * *"
}

fetch = Http {
  label: "Fetch SF Weather"
  url: "https://api.open-meteo.com/v1/forecast?latitude=37.7749&longitude=-122.4194&current=temperature_2m,wind_speed_10m,relative_humidity_2m,weather_code"
  method: "GET"
}

parse = ExecPython(
  raw: String,
  status: Number
) -> (
  weather: Dict[String, String | Number],
  error: String
) {
  label: "Parse Weather"
  code: ```
import json

if status < 200 or status >= 300:
    return {"weather": None, "error": f"HTTP {status}: {raw}"}

try:
    data = json.loads(raw)
    current = data.get("current", {})
    units = data.get("current_units", {})
    weather = {
        "temperature": f"{current.get('temperature_2m')} {units.get('temperature_2m', '')}",
        "wind_speed": f"{current.get('wind_speed_10m')} {units.get('wind_speed_10m', '')}",
        "humidity": f"{current.get('relative_humidity_2m')} {units.get('relative_humidity_2m', '')}",
        "weather_code": current.get("weather_code"),
        "time": current.get("time")
    }
    return {"weather": weather, "error": None}
except Exception as e:
    return {"weather": None, "error": str(e)}
  ```
}
parse.raw = fetch.body
parse.status = fetch.status

log_weather = Debug { label: "Weather Log" }
log_weather.data = parse.weather

log_error = Debug { label: "Error Log" }
log_error.data = parse.error

